import React from 'react';
import Footer from "../components/PageComponents/Footer";
import Navbar from "../components/PageComponents/Navbar";
import NotFoundPage from "../features/NotFoundPage";
import { Typography, Button, Paper, Box } from '@mui/material';
import useDatasetDetails from '../hooks/useDetailPage';

const DetailPage = () => {
    const { dataset, sectionId, handleDownload } = useDatasetDetails();

    if (!dataset) {
        return (
            <div>
                <Navbar />
                <NotFoundPage />
            </div>
        );
    }

    // Placeholder JSON structure
    const placeholderJSON = {
        title: "Sample Dataset",
        description: "This is a placeholder description for the dataset.",
        id: "dataset-123",
        fileType: "csv",
        fileUrl: "/datasets/sample-dataset.csv",
        promptType: "base-prompt",
    };

    return (
        <Box sx={{ display: 'flex', flexDirection: 'column', minHeight: '100vh' }}>
            <Navbar />
            <Box component="main" sx={{ flexGrow: 1 }}> {/* This box will grow */}
                <Paper style={{ padding: '20px', marginTop: '20px' }}>
                    <Typography variant='h4' component='h1' sx={{ fontFamily: 'monospace' }} gutterBottom>
                        {dataset.title}
                    </Typography>
                    <Button 
                        onClick={() => handleDownload(dataset.fileUrl, dataset.id, dataset.fileType)}
                        variant='contained' 
                        color='primary' 
                        style={{ marginBottom: '20px', marginRight: '20px', fontFamily: 'monospace' }}
                    >
                        Download Dataset
                    </Button>
                    {sectionId.includes('manual') && (
                        <Button
                            onClick={() => handleDownload(dataset.fileUrl, dataset.id, dataset.promptType)}
                            variant='contained' 
                            color='primary' 
                            style={{ marginBottom: '20px', fontFamily: 'monospace' }}
                        >
                            Download Base Prompt
                        </Button>
                    )}
                    <Typography variant='h5' component='h2' sx={{ fontFamily: 'monospace', fontWeight: 600, marginBottom: '10px' }}>
                        About Dataset
                    </Typography>
                    <Typography variant='body1' sx={{ fontFamily: 'monospace' }}>
                        {dataset.description}
                    </Typography>

                    {/* JSON Structure Display */}
                    <Typography variant='h5' component='h2' sx={{ fontFamily: 'monospace', fontWeight: 600, marginTop: '20px', marginBottom: '10px' }}>
                        JSON Structure
                    </Typography>
                    <Paper elevation={3} sx={{ padding: '15px', backgroundColor: '#f4f4f4' }}>
                        <pre style={{ fontFamily: 'monospace', fontSize: '14px' }}>
                            {dataset ? JSON.stringify(dataset, null, 2) : JSON.stringify(placeholderJSON, null, 2)}  {/* Displaying JSON or placeholder */}
                        </pre>
                    </Paper>
                </Paper>
            </Box>
            <Footer />
        </Box>
    );
};

export default DetailPage;
